#include <stdio.h>
#include <string.h>
#include <ctype.h>
#include <stdlib.h>
#define MAX_LINE 10005
#define MAX_WORDS 10005
#define MAX_WORD_LEN 101

typedef struct {
    char word[MAX_WORD_LEN];
    int cnt;
} Entry;

int cmpEntry(const void *a, const void *b) {
    const Entry *ea = (const Entry *)a;
    const Entry *eb = (const Entry *)b;
    return strcmp(ea->word, eb->word);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char line[MAX_LINE];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        // to lowercase
        for (char *p = line; *p; ++p) *p = tolower(*p);
        // split into words
        char *token = strtok(line, " ");
        Entry entries[MAX_WORDS];
        int uniq = 0;
        while (token) {
            int found = -1;
            for (int i = 0; i < uniq; ++i) {
                if (strcmp(entries[i].word, token) == 0) { found = i; break; }
            }
            if (found >= 0) {
                entries[found].cnt++;
            } else {
                strncpy(entries[uniq].word, token, MAX_WORD_LEN - 1);
                entries[uniq].word[MAX_WORD_LEN - 1] = '\0';
                entries[uniq].cnt = 1;
                uniq++;
            }
            token = strtok(NULL, " ");
        }
        qsort(entries, uniq, sizeof(Entry), cmpEntry);
        for (int i = 0; i < uniq; ++i) {
            printf("%s: %d\n", entries[i].word, entries[i].cnt);
        }
        if (tc != T - 1) printf("\n");
    }
    return 0;
}

