    cin.tie(nullptr);
    int T;
    if(!(cin>>T)) return 0;
    string dummy; getline(cin, dummy); // consume endline after T
    for(int tc=0; tc<T; ++tc){
        string line; getline(cin, line);
        for(char &c: line) c = tolower(c);
        unordered_map<string,int> freq;
        stringstream ss(line);
        string w;
        while(ss>>w) freq[w]++;
        vector<string> keys; keys.reserve(freq.size());
        for(const auto &p: freq) keys.push_back(p.first);
        sort(keys.begin(), keys.end());
        for(const string &k: keys) cout << k << ": " << freq[k] << "\n";
        if(tc != T-1) cout << "\n";
    }
    return 0;
}

