import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out_lines = []
    for i in range(1, T+1):
        line = data[i].strip().lower()
        words = line.split(' ')
        freq = {}
        for w in words:
            freq[w] = freq.get(w, 0) + 1
        for w in sorted(freq):
            out_lines.append(f"{w}: {freq[w]}")
        if i != T:
            out_lines.append('')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

