const fs = require('fs');
const input = fs.readFileSync(0, 'utf8').trim().split('\n');
if (input.length === 0) process.exit(0);
const T = parseInt(input[0].trim(), 10);
let output = [];
for (let tc = 1; tc <= T; tc++) {
  let line = input[tc] ? input[tc].trim().toLowerCase() : '';
  const words = line.split(' ');
  const map = new Map();
  for (const w of words) {
    map.set(w, (map.get(w) || 0) + 1);
  }
  const sorted = Array.from(map.keys()).sort();
  for (const w of sorted) {
    output.push(`${w}: ${map.get(w)}`);
  }
  if (tc !== T) output.push('');
}
